y */\n.et_pb_section[class*="tb_body"].et_section_regular{background:transparent !important;background-image:none !important;padding:0 !important;margin:0 !important}\n.et_pb_row[class*="tb_body"].et_pb_row{max-width:100% !important;width:100% !important;padding:0 !important;margin:0 !important}\n.et_pb_column[class*="tb_body"]{padding:0 !important;margin:0 !important}\n@media(max-width:640px){\n  .et_pb_section .et_pb_row[class*="tb_body"].et_pb_row{padding:0 !important}\n}</style><!-- /wp:html -->\n<!-- wp:divi/section {"module":{"meta":{"adminLabel":{"desktop":{"value":"Auto Hero"}}},"decoration":{"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px","syncVertical":"off","syncHorizontal":"off"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{background:transparent !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/row {"module":{"meta":{"adminLabel":{"desktop":{"value":"Auto Hero: Row"}}},"decoration":{"layout":{"desktop":{"value":{"flexWrap":"nowrap","display":"flex","flexDirection":"row","rowGap":"0px","columnGap":"0px"}}},"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{max-width:100% !important;margin:0 !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/column {"module":{"meta":{"adminLabel":{"desktop":{"value":"Auto Hero: Column"}}},"decoration":{}},"css":{"desktop":{"value":{"freeForm":"selector{width:100% !important;padding:0 !important;}"}}}} -->\n<!-- wp:html --><div class="auto-hero">\n    <div class="dw-d-bg dw-d-bg--left dw-d-bg--gradient" style="opacity: 0.14;"></div>\n            <div class="auto-hero-inner" style="position: relative; z-index: 2;">\n                <div class="auto-hero-badge">\n                    <span>Automotive Parts Manufacturing</span>\n                </div>\n                <h1>Built for What <span>OEMs Demand</span></h1>\n                <p class="auto-hero-subtitle">JIT delivery. Complete traceability. EDI integration. Thailand is ASEAN\'s automotive hub—we help tier 1-3 suppliers stay competitive.</p>\n                <div class="auto-hero-stats">\n                    <div class="auto-hero-stat">\n                        <div class="auto-hero-stat-value">500+</div>\n                        <div class="auto-hero-stat-label">Auto suppliers served</div>\n                    </div>\n                    <div class="auto-hero-stat">\n                        <div class="auto-hero-stat-value">100%</div>\n                        <div class="auto-hero-stat-label">Traceability coverage</div>\n                    </div>\n                    <div class="auto-hero-stat">\n                        <div class="auto-hero-stat-value">99.5%</div>\n                        <div class="auto-hero-stat-label">On-time delivery</div>\n                    </div>\n                </div>\n            </div>\n    </div><!-- /wp:html -->\n<!-- /wp:divi/column -->\n<!-- /wp:divi/row -->\n<!-- /wp:divi/section -->\n<!-- wp:divi/section {"module":{"meta":{"adminLabel":{"desktop":{"value":"Context"}}},"decoration":{"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px","syncVertical":"off","syncHorizontal":"off"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{background:transparent !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/row {"module":{"meta":{"adminLabel":{"desktop":{"value":"Context: Row"}}},"decoration":{"layout":{"desktop":{"value":{"flexWrap":"nowrap","display":"flex","flexDirection":"row","rowGap":"0px","columnGap":"0px"}}},"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{max-width:100% !important;margin:0 !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/column {"module":{"meta":{"adminLabel":{"desktop":{"value":"Context: Column"}}},"decoration":{}},"css":{"desktop":{"value":{"freeForm":"selector{width:100% !important;padding:0 !important;}"}}}} -->\n<!-- wp:html --><div class="context-section">\n    <div class="context-inner">\n                <h2>Thailand: ASEAN\'s Detroit</h2>\n                <p>Thailand produces <strong>1.9 million vehicles annually</strong>, making it the largest automotive manufacturing hub in Southeast Asia. Behind every vehicle are <strong>2,500+ tier 1-3 suppliers</strong> facing relentless demands: perfect quality, complete traceability, and JIT delivery windows measured in hours, not days. DigiWin has spent 20+ years helping these suppliers meet—and exceed—OEM expectations.</p>\n            </div>\n    </div><!-- /wp:html -->\n<!-- /wp:divi/column -->\n<!-- /wp:divi/row -->\n<!-- /wp:divi/section -->\n<!-- wp:divi/section {"module":{"meta":{"adminLabel":{"desktop":{"value":"Stakes"}}},"decoration":{"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px","syncVertical":"off","syncHorizontal":"off"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{background:transparent !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/row {"module":{"meta":{"adminLabel":{"desktop":{"value":"Stakes: Row"}}},"decoration":{"layout":{"desktop":{"value":{"flexWrap":"nowrap","display":"flex","flexDirection":"row","rowGap":"0px","columnGap":"0px"}}},"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{max-width:100% !important;margin:0 !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/column {"module":{"meta":{"adminLabel":{"desktop":{"value":"Stakes: Column"}}},"decoration":{}},"css":{"desktop":{"value":{"freeForm":"selector{width:100% !important;padding:0 !important;}"}}}} -->\n<!-- wp:html --><div class="stakes-section">\n    <div class="dw-section-scene">\n                <svg aria-hidden="true" viewBox="0 0 1400 900" fill="none" xmlns="http://www.w3.org/2000/svg" preserveAspectRatio="xMidYMid slice">\n                    <line x1="0" y1="450" x2="1400" y2="450" stroke="#000864" stroke-width="1.5" opacity="0.1"/>\n                    <rect x="100" y="400" width="90" height="100" rx="6" stroke="#000864" stroke-width="2" fill="none" opacity="0.15"/>\n                    <text x="145" y="460" font-family="\'Noto Sans\',sans-serif" font-size="8" font-weight="600" fill="#000864" opacity="0.1" text-anchor="middle">STAMP</text>\n                    <path d="M190 450 L320 450" stroke="#000864" stroke-width="1.5" opacity="0.12"/>\n                    <polygon points="315,445 330,450 315,455" fill="#000864" opacity="0.12"/>\n                    <rect x="330" y="400" width="90" height="100" rx="6" stroke="#000864" stroke-width="2" fill="none" opacity="0.15"/>\n                    <text x="375" y="460" font-family="\'Noto Sans\',sans-serif" font-size="8" font-weight="600" fill="#000864" opacity="0.1" text-anchor="middle">WELD</text>\n                    <path d="M420 450 L550 450" stroke="#000864" stroke-width="1.5" opacity="0.12"/>\n                    <polygon points="545,445 560,450 545,455" fill="#000864" opacity="0.12"/>\n                    <rect x="560" y="400" width="90" height="100" rx="6" stroke="#000864" stroke-width="2" fill="none" opacity="0.15"/>\n                    <text x="605" y="460" font-family="\'Noto Sans\',sans-serif" font-size="8" font-weight="600" fill="#000864" opacity="0.1" text-anchor="middle">PAINT</text>\n                    <path d="M650 450 L780 450" stroke="#000864" stroke-width="1.5" opacity="0.12"/>\n                    <polygon points="775,445 790,450 775,455" fill="#000864" opacity="0.12"/>\n                    <rect x="790" y="400" width="90" height="100" rx="6" stroke="#000864" stroke-width="2" fill="none" opacity="0.15"/>\n                    <text x="835" y="460" font-family="\'Noto Sans\',sans-serif" font-size="8" font-weight="600" fill="#000864" opacity="0.1" text-anchor="middle">ASSEM</text>\n                    <path d="M880 450 L1010 450" stroke="#000864" stroke-width="1.5" opacity="0.12"/>\n                    <polygon points="1005,445 1020,450 1005,455" fill="#000864" opacity="0.12"/>\n                    <rect x="1020" y="400" width="90" height="100" rx="6" stroke="#000864" stroke-width="2" fill="none" opacity="0.15"/>\n                    <text x="1065" y="460" font-family="\'Noto Sans\',sans-serif" font-size="8" font-weight="600" fill="#000864" opacity="0.1" text-anchor="middle">QC</text>\n                    <text x="1200" y="300" font-family="\'Noto Sans\',sans-serif" font-size="16" font-weight="700" fill="#00AFF0" opacity="0.1">JIT</text>\n                    <rect x="1150" y="310" width="120" height="40" rx="4" stroke="#00AFF0" stroke-width="1.5" fill="none" opacity="0.1"/>\n                    <text x="1210" y="335" font-family="\'Noto Sans\',sans-serif" font-size="9" font-weight="600" fill="#00AFF0" opacity="0.08" text-anchor="middle">EDI LINK</text>\n                    <circle cx="300" cy="250" r="3" fill="#000864" opacity="0.08"/>\n                    <circle cx="700" cy="650" r="4" fill="#00AFF0" opacity="0.08"/>\n                    <circle cx="1100" cy="700" r="3" fill="#000864" opacity="0.06"/>\n                </svg>\n            </div>\n            <div class="stakes-inner" style="position: relative; z-index: 2;">\n                <div class="stakes-header">\n                    <h2>The Automotive Stakes Are High</h2>\n                    <p>In automotive, there\'s no room for "good enough"</p>\n                </div>\n                <div class="stakes-grid">\n                    <div class="stake-card">\n                        <div class="stake-icon">\n                            <svg aria-hidden="true" viewBox="0 0 24 24"><circle cx="12" cy="12" r="10"/><polyline points="12 6 12 12 16 14"/></svg>\n                        </div>\n                        <h3>JIT or Else</h3>\n                        <p>Miss one delivery window and the OEM stops the line. The penalty isn\'t a warning—it\'s the cost of that downtime, plus losing the contract entirely.</p>\n                    </div>\n                    <div class="stake-card">\n                        <div class="stake-icon">\n                            <svg aria-hidden="true" viewBox="0 0 24 24"><circle cx="11" cy="11" r="8"/><line x1="21" y1="21" x2="16.65" y2="16.65"/></svg>\n                        </div>\n                        <h3>Trace or Lose</h3>\n                        <p>A quality issue surfaces. OEM asks: which lot? Which raw materials? Which operator? If you can\'t answer in hours, you\'re not a tier-1 supplier anymore.</p>\n                    </div>\n                    <div class="stake-card">\n                        <div class="stake-icon">\n                            <svg aria-hidden="true" viewBox="0 0 24 24"><path d="M16 4h2a2 2 0 0 1 2 2v14a2 2 0 0 1-2 2H6a2 2 0 0 1-2-2V6a2 2 0 0 1 2-2h2"/><rect x="8" y="2" width="8" height="4" rx="1" ry="1"/><line x1="9" y1="12" x2="15" y2="12"/><line x1="9" y1="16" x2="15" y2="16"/></svg>\n                        </div>\n                        <h3>Audit Anxiety</h3>\n                        <p>IATF 16949. Customer audits quarterly. Documentation requirements that keep growing. Manual systems simply can\'t keep up.</p>\n                    </div>\n                </div>\n            </div>\n    </div><!-- /wp:html -->\n<!-- /wp:divi/column -->\n<!-- /wp:divi/row -->\n<!-- /wp:divi/section -->\n<!-- wp:divi/section {"module":{"meta":{"adminLabel":{"desktop":{"value":"Solutions"}}},"decoration":{"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px","syncVertical":"off","syncHorizontal":"off"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{background:transparent !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/row {"module":{"meta":{"adminLabel":{"desktop":{"value":"Solutions: Row"}}},"decoration":{"layout":{"desktop":{"value":{"flexWrap":"nowrap","display":"flex","flexDirection":"row","rowGap":"0px","columnGap":"0px"}}},"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{max-width:100% !important;margin:0 !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/column {"module":{"meta":{"adminLabel":{"desktop":{"value":"Solutions: Column"}}},"decoration":{}},"css":{"desktop":{"value":{"freeForm":"selector{width:100% !important;padding:0 !important;}"}}}} -->\n<!-- wp:html --><div class="solutions-section">\n    <div class="dw-d-bg dw-d-bg--corner-br" style="opacity: 0.08;"></div>\n            <div class="solutions-inner" style="position: relative; z-index: 2;">\n                <div class="solutions-header">\n                    <h2>How DigiWin Solves It</h2>\n                    <p>Purpose-built capabilities for automotive supply chain</p>\n                </div>\n                <div class="solutions-grid">\n                    <div class="solution-card">\n                        <div class="solution-icon">\n                            <svg aria-hidden="true" viewBox="0 0 24 24"><path d="M6.5 12a5.5 5.5 0 1 0 11 0 5.5 5.5 0 1 0-11 0"/><path d="M3 12a9 9 0 1 0 18 0 9 9 0 1 0-18 0"/><circle cx="12" cy="12" r="2"/></svg>\n                        </div>\n                        <h3>OEM EDI Integration</h3>\n                        <p>Electronic exchange of forecasts, POs, and delivery confirmations with your OEM customers. No manual data entry, no missed signals.</p>\n                        <div class="solution-features">\n                            <div class="solution-feature">\n                                <svg aria-hidden="true" viewBox="0 0 20 20" fill="currentColor"><path fill-rule="evenodd" d="M16.707 5.293a1 1 0 010 1.414l-8 8a1 1 0 01-1.414 0l-4-4a1 1 0 011.414-1.414L8 12.586l7.293-7.293a1 1 0 011.414 0z"/></svg>\n                                <span>Receive forecasts & POs automatically</span>\n                            </div>\n                            <div class="solution-feature">\n                                <svg aria-hidden="true" viewBox="0 0 20 20" fill="currentColor"><path fill-rule="evenodd" d="M16.707 5.293a1 1 0 010 1.414l-8 8a1 1 0 01-1.414 0l-4-4a1 1 0 011.414-1.414L8 12.586l7.293-7.293a1 1 0 011.414 0z"/></svg>\n                                <span>Send ASN & delivery confirmations</span>\n                            </div>\n                            <div class="solution-feature">\n                                <svg aria-hidden="true" viewBox="0 0 20 20" fill="currentColor"><path fill-rule="evenodd" d="M16.707 5.293a1 1 0 010 1.414l-8 8a1 1 0 01-1.414 0l-4-4a1 1 0 011.414-1.414L8 12.586l7.293-7.293a1 1 0 011.414 0z"/></svg>\n                                <span>Quality data exchange</span>\n                            </div>\n                        </div>\n                    </div>\n                    <div class="solution-card">\n                        <div class="solution-icon">\n                            <svg aria-hidden="true" viewBox="0 0 24 24"><path d="M20.59 13.41l-7.17 7.17a2 2 0 0 1-2.83 0L2 12V2h10l8.59 8.59a2 2 0 0 1 0 2.82z"/><line x1="7" y1="7" x2="7.01" y2="7"/></svg>\n                        </div>\n                        <h3>Lot-Level Traceability</h3>\n                        <p>Track every component from receiving through shipping. Answer "where did this part go?" in seconds, not days.</p>\n                        <div class="solution-features">\n                            <div class="solution-feature">\n                                <svg aria-hidden="true" viewBox="0 0 20 20" fill="currentColor"><path fill-rule="evenodd" d="M16.707 5.293a1 1 0 010 1.414l-8 8a1 1 0 01-1.414 0l-4-4a1 1 0 011.414-1.414L8 12.586l7.293-7.293a1 1 0 011.414 0z"/></svg>\n                                <span>Forward & backward traceability</span>\n                            </div>\n                            <div class="solution-feature">\n                                <svg aria-hidden="true" viewBox="0 0 20 20" fill="currentColor"><path fill-rule="evenodd" d="M16.707 5.293a1 1 0 010 1.414l-8 8a1 1 0 01-1.414 0l-4-4a1 1 0 011.414-1.414L8 12.586l7.293-7.293a1 1 0 011.414 0z"/></svg>\n                                <span>Barcode/QR code scanning</span>\n                            </div>\n                            <div class="solution-feature">\n                                <svg aria-hidden="true" viewBox="0 0 20 20" fill="currentColor"><path fill-rule="evenodd" d="M16.707 5.293a1 1 0 010 1.414l-8 8a1 1 0 01-1.414 0l-4-4a1 1 0 011.414-1.414L8 12.586l7.293-7.293a1 1 0 011.414 0z"/></svg>\n                                <span>Recall scope analysis</span>\n                            </div>\n                        </div>\n                    </div>\n                    <div class="solution-card">\n                        <div class="solution-icon">\n                            <svg aria-hidden="true" viewBox="0 0 24 24"><rect x="3" y="4" width="18" height="18" rx="2" ry="2"/><line x1="16" y1="2" x2="16" y2="6"/><line x1="8" y1="2" x2="8" y2="6"/><line x1="3" y1="10" x2="21" y2="10"/></svg>\n                        </div>\n                        <h3>Kanban & JIT Scheduling</h3>\n                        <p>Production scheduling that understands kanban signals, sequence orders, and delivery windows.</p>\n                        <div class="solution-features">\n                            <div class="solution-feature">\n                                <svg aria-hidden="true" viewBox="0 0 20 20" fill="currentColor"><path fill-rule="evenodd" d="M16.707 5.293a1 1 0 010 1.414l-8 8a1 1 0 01-1.414 0l-4-4a1 1 0 011.414-1.414L8 12.586l7.293-7.293a1 1 0 011.414 0z"/></svg>\n                                <span>Plan backwards from ship date</span>\n                            </div>\n                            <div class="solution-feature">\n                                <svg aria-hidden="true" viewBox="0 0 20 20" fill="currentColor"><path fill-rule="evenodd" d="M16.707 5.293a1 1 0 010 1.414l-8 8a1 1 0 01-1.414 0l-4-4a1 1 0 011.414-1.414L8 12.586l7.293-7.293a1 1 0 011.414 0z"/></svg>\n                                <span>Sequence delivery support</span>\n                            </div>\n                            <div class="solution-feature">\n                                <svg aria-hidden="true" viewBox="0 0 20 20" fill="currentColor"><path fill-rule="evenodd" d="M16.707 5.293a1 1 0 010 1.414l-8 8a1 1 0 01-1.414 0l-4-4a1 1 0 011.414-1.414L8 12.586l7.293-7.293a1 1 0 011.414 0z"/></svg>\n                                <span>Multi-plant coordination</span>\n                            </div>\n                        </div>\n                    </div>\n                    <div class="solution-card">\n                        <div class="solution-icon">\n                            <svg aria-hidden="true" viewBox="0 0 24 24"><path d="M9 11l3 3L22 4"/><path d="M21 12v7a2 2 0 0 1-2 2H5a2 2 0 0 1-2-2V5a2 2 0 0 1 2-2h11"/></svg>\n                        </div>\n                        <h3>Quality Documentation</h3>\n               